var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"윽, 더는 안 닿는 것 같아요.","JPN":"うっ、これ以上は届かないようです。","ENG":"Ugh, it doesn't seem to reach anymore.","TWN":"呃，碰不到了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"당연한 거지만, 카운터의 능력은 자기 몸에서 멀어질수록 약해져.","JPN":"当たり前だけど、カウンター能力は自分の体から遠ざかるほど弱くなるわ。","ENG":"Naturally, a Counter's ability weakens the farther it is from the body.","TWN":"這是當然的，制裁者的能力離自己身體越遠就越弱。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 네 능력은… 지금 너와 나 사이의 거리가 한계인 모양이네.","JPN":"そしてあなたの能力は……今あなたと私の間の、この距離が限界のようね。","ENG":"And your ability... It seems like the distance between you and me is the limit right now.","TWN":"至於你的能力嘛……看來你和我之間的距離就是你的極限了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"자신의 한계는 숙지해두는 편이 실전에 도움이 될 거야.","JPN":"自分の限界を知っておくと実践で役に立つわ。","ENG":"Knowing your own limits will help in real situations.","TWN":"了解自己的極限對實戰有幫助。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Okay!","TWN":"是的！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 여기서 문제- 네 능력 범위를 벗어난 무장범죄자가 있다면 어떻게 잡아야 할까?","JPN":"では、ここで問題。あなたの能力範囲を越えた位置に武装した犯罪者がいる場合はどうやって捕まえる？","ENG":"Here's a question. What would you do if there's an armed criminal outside your ability's range.","TWN":"那麼問題來了——如果有超出你能力範圍的武裝罪犯，你該如何抓住他呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"정답-! 달려가서 거리를 좁혀요!","JPN":"は～い！　走って距離を縮めます！","ENG":"I know! Run and close the distance!","TWN":"快跑過去拉近距離！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"틀린 얘기는 아니네. 하지만 그 범죄자가 너랑 똑같은 속도로 도망친다면 어때?","JPN":"間違ってはいないわね。でもその犯罪者があなたと同じスピードで逃げるとしたら？","ENG":"That's not wrong. But what if the criminal runs away at the same speed as you?","TWN":"說得沒錯。但是如果那個罪犯跑得和你一樣快呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그건 치사하네요!","JPN":"それはズルいです！","ENG":"That's unfair!","TWN":"那樣也太卑鄙了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"싸움이란 건 원래 그렇게 하는 거야. 단순히 더 강한 쪽이 아니라 상황을 더 유리하게 이끄는 쪽이 이기는 거지.","JPN":"戦いとはそういうものなの。単に強い方が勝つのではなく、状況をより有利に持って行った方が勝つ。","ENG":"Fighting is just like that. It's not always about who's stronger, but who can turn the situation in their favor.","TWN":"戰鬥本來就是這樣進行的。勝利的並不僅僅是更強的一方，還是能夠將局勢引向更有利方向的一方。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럴 땐 상대를 도발해봐. 너에게 다가올 수 밖에 없도록.","JPN":"そういう時は相手を挑発してみて。あなたに近づかざるを得ないように。","ENG":"When that happens, try provoking the opponent. Make them have no choice but to approach you.","TWN":"那時就挑釁對手吧，讓他們不得不靠近你。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"도발이 뭔가요?","JPN":"挑発って何ですか？","ENG":"\\"Provoke?\\" What does that mean?","TWN":"挑釁是什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"상대를 기분 나쁘게 하는 거지. 단순히 욕을 하거나 없는 말을 지어내서 자극하는 거야.","JPN":"相手の気を逆撫でるのよ。悪口を言ったり、話を捏造して刺激するの。","ENG":"It means making them upset. Simply insult them or use lies to trigger them.","TWN":"讓對方生氣，用髒話或謊言來刺激對方。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"근처에 범죄자의 동료가 있다면 그 녀석 목숨으로 협박해도 되고.","JPN":"近くに犯罪者の仲間がいる場合は、そいつの命で脅してもいい。","ENG":"If the criminal has an accomplice nearby, you can use that person as leverage to threaten the criminal.","TWN":"如果附近有罪犯的同夥，可以用他的性命來威脅。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래도 되나요?","JPN":"そんなことしていいんですか？","ENG":"Is that really okay?","TWN":"那樣也可以嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"지금은 너무하다고 생각하겠지만… 겪어보면 알게 될 거야.","JPN":"今は酷いと思うかもしれないけど……実際経験すればわかるようになるよ。","ENG":"It might feel harsh right now, but... you'll understand once you go through it.","TWN":"現在你可能覺得太過分了……但經歷過後你就會明白的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇게 해서라도 이겨야만 한다고 느끼는 때가 올 테니…","JPN":"そうしてでも勝たなければならないと思う時が来るから……","ENG":"There will come a time when you'll feel that winning is the only option, no matter how it happens.","TWN":"總有一天，你會覺得，只要能贏，哪怕用這種方法也無所謂。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_04"},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"꺄아!!","JPN":"きゃあ！！","ENG":"Kyaaah!!","TWN":"啊！！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_COFFIN_LASER_MAIN_EXPLOSION"},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"방금 뭐였지?","JPN":"何が起きたの？","ENG":"What was that just now?","TWN":"剛剛那是什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"우, 운석이다! 저기로 운석 같은 게 떨어졌어!","JPN":"い、隕石だ！　隕石のような物があそこに落ちた！","ENG":"A m-meteorite! Something like a meteorite just fell over there!","TWN":"啊，隕石！那邊掉下來了一個像隕石的東西！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"운석이라고?","JPN":"隕石？","ENG":"A meteorite?","TWN":"隕石？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잠깐… 저 방향은?","JPN":"待って……あの方向は？","ENG":"Wait... that direction is?","TWN":"等等……那個方向？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 서윤? 저도 같이 갈래요!","JPN":"あっ、シズカさん？　置いて行かないでください！","ENG":"Seo Yoon! Wait for me!","TWN":"啊，徐芸？我也一起去！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"상황 보고해.","JPN":"状況を報告しろ。","ENG":"Proceed with the status report.","TWN":"報告情況。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"2차 폭발을 막기 위해 3-3구획의 가스와 전력 공급을 모두 차단했습니다.","JPN":"2次爆発を防ぐために3-3区画のガスと電力供給をすべて遮断しました。","ENG":"To prevent a secondary explosion, the gas and power supply in block 3-3 have been completely shut off.","TWN":"為了阻止二次爆炸，已關閉3-3區塊的所有燃氣和電力供應。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"민가 2채가 무너지긴 했지만, 다행히 추락체에 의한 인명피해는 없는 걸로 파악됩니다.","JPN":"民家2軒が崩壊しましたが、幸い落下体による人的被害はいないようです。","ENG":"Two residential buildings have collapsed, but fortunately, there are no casualties from the fallen object.","TWN":"雖然有兩棟民房倒塌，但幸運的是沒有因墜落物造成的傷亡。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"추락 현장에서 낮은 침식파가 감지되고 있어요. 최초 보고처럼 일반적인 운석은 아닌 것 같습니다.","JPN":"落下現場で低レベルの侵食波が感知されています。当初の報告にあったようにただの隕石ではないようです。","ENG":"A low-level Corruption ray is being detected at the crash site. It doesn't seem to be the typical meteorite as initially reported.","TWN":"在墜落現場檢測到低強度的侵蝕波，看來不像最初報告的那樣是普通的隕石。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"뭐, 운석인 시점에서 일반과는 거리가 멀지만 말이죠.","JPN":"まぁ、隕石という点で既に普通とはかけ離れていますが。","ENG":"Well, given that it's a meteorite, it's already far from being typical.","TWN":"畢竟既然有侵蝕波，就表示不是普通的隕石。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"아깝네요. 운석을 팔면 돈이 된다던데.","JPN":"残念です。本物の隕石なら結構なお金になるらしいのに。","ENG":"What a pity. If it were a real meteorite, it could be worth quite a bit.","TWN":"真可惜。如果真的是隕石的話，還能賣不少錢呢。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"정체가 뭔지는 직접 보면 알게 되겠지. 우리가 현장 건물 내부로 진입하겠다.","JPN":"正体が何かは直接見ればわかるだろう。私たちが現場の建物内部に入る。","ENG":"We'll find out its true identity once we see it for ourselves. We're heading into the building now.","TWN":"具體是什麼東西，進去就知道了。我們現在要進入建築的內部。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"침식파가 감지된다는데, 태스크포스가 올 때까지 기다리는 게 좋지 않을까요?","JPN":"侵食波が感知されていることですし、タスクフォースが来るまで待ったほうがいいのでは？","ENG":"Given that a Corruption ray is being detected, wouldn't it be better to wait for a TASKFORCE to arrive?","TWN":"既然檢測到了侵蝕波，那還是等特遣勢力來吧？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"그럴 시간 없다. 그 추락체가 위험한 불씨라면 최대한 빨리 제거하는 게 우선이니까.","JPN":"そんな時間はない。あの落下体が危険な火種なら、まずはできる限り早く除去することだ。","ENG":"There's no time for that. If the fallen object is a dangerous spark, the priority is to remove it as quickly as possible.","TWN":"沒時間了。如果那個墜落物是危險的火種，要儘快清除它。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"블랙타이드에서 온 재난대응팀 분들이죠?","JPN":"ブラックタイドから来た災害対応チームの方々ですね？","ENG":"You're from the disaster response team from Black Tide, right?","TWN":"是來自黑潮的災難應對小組吧？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저도 같이 도와드릴게요.","JPN":"私も手伝います。","ENG":"I'll help out as well.","TWN":"我也會一起幫忙的。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"…카운터인가? 마음은 고맙지만 우린 규정상 신원이 불분명한 카운터와는 움직이지 않아.","JPN":"……カウンターかね？　気持ちはありがたいが私たちは規定上、身元不明のカウンターとは行動を共にできないんだ。","ENG":"...A Counter? We appreciate the offer, but we can't work with a Counter whose identity is not verified, according to regulations.","TWN":"……是制裁者嗎？非常感謝你，但我們按規定不能和身份不明的制裁者一起行動。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런가요? 이런 건 보여드릴 수 있는데.","JPN":"そうですか？　こういうのはお見せできますけど。","ENG":"Is that so? I can show you something like this.","TWN":"是這樣嗎？我可以給你看這個。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"저기… 죄송하지만 태스크포스 소속이라고 하셔도 개인의 권한만으로는…","JPN":"あの……申し訳ありませんがタスクフォース所属だとしても個人の権限だけでは……","ENG":"Excuse me, but even if you say you're with a TASKFORCE, with individual authority alone–","TWN":"那個……很抱歉，就算你是特遣勢力的成員，也不能僅憑個人許可權……"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"선배님? 이 아가씨, 관리국 정식 라이선스를 갖고 있는데요?","JPN":"先輩？　このお嬢さん、管理局の正式ライセンスを持っていますよ？","ENG":"Wait, this young lady has an official license from the Administration.","TWN":"前輩，這位小姐有管理局正式執照喔！"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"휘유, 보기랑 다르게 산전수전 다 겪으신 베테랑 분이셨구만.","JPN":"ひゅう、見た目と違って経験豊富なベテランだったんすね。","ENG":"Phew, I didn't expect you to be such a seasoned veteran from the looks of it.","TWN":"呼，原來是身經百戰的老手啊。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"우리야 사고 현장을 집처럼 드나드는 게 본업이지만, 아가씨 같은 3자가 굳이 위험을 무릅쓸 이유라도 있나?","JPN":"私たちは自分の家のごとく事故現場に出入りすることが仕事だが、お嬢さんのような第三者がわざわざ危険に足を突っ込むのには何か理由でもあるのか？","ENG":"It's our job to visit accident sites like it's our home, but there's no reason for someone like you to take unnecessary risks, right?","TWN":"我們是以事故現場為家，但像小姐這樣的外人，何必冒險呢？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼요.","JPN":"もちろんです。","ENG":"Of course there is.","TWN":"當然了。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이 사고 현장이 방금 전까진 저희 집이었던 곳이라서요.","JPN":"この事故現場は、少し前まで私の家でしたから。","ENG":"This accident site was actually where my home used to be until just a moment ago.","TWN":"因為這個事故現場，直到剛才還是我們的家。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"…오.","JPN":"……おぉ。","ENG":"...Oh.","TWN":"……噢。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"저런.","JPN":"これはこれは。","ENG":"Oh no.","TWN":"喔。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"유감이네요.","JPN":"残念ですね。","ENG":"I feel sorry for you.","TWN":"真是令人遺憾。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"내가 앞장서지. 적당히 떨어져서 와라.","JPN":"私が先頭に立つ。適当な距離を維持しつつ付いて来い。","ENG":"I'll take the lead. Stay back a bit.","TWN":"我來帶路，你們保持適當距離跟上。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};